import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', location: '', startDate: '', endDate: '', 
    description: '', importantNotes: '', capacity: '', 
    price: '', discount: '', status: 'Available'
  });

  useEffect(() => {
    if (editingTour) {
      // 轉換日期格式以適應 HTML date input (YYYY-MM-DD)
      const formattedData = { ...editingTour };
      if (editingTour.startDate) formattedData.startDate = editingTour.startDate.split('T')[0];
      if (editingTour.endDate) formattedData.endDate = editingTour.endDate.split('T')[0];
      setFormData(formattedData);
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const config = { headers: { Authorization: `Bearer ${user.token}` } };
      const { _id, __v, createdAt, updatedAt, ...payload } = formData;

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, payload, config);
      } else {
        await axiosInstance.post('/api/tours', payload, config);
      }
      alert('Success!');
      onSuccess();
    } catch (error) {
      alert('Save failed: ' + (error.response?.data?.message || 'Check Server'));
    }
  };

  const handleDelete = async () => {
    if (!window.confirm("Are you sure you want to delete this package?")) return;
    try {
      await axiosInstance.delete(`/api/tours/${editingTour._id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      alert('Deleted!');
      onSuccess();
    } catch (error) {
      alert('Delete failed');
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-white">
      {/* 1. Header (對齊 Figma) */}
      <div className="flex justify-between items-center p-5 border-b sticky top-0 bg-white z-10">
        <button type="button" onClick={onClose} className="text-2xl text-gray-800">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <h1 className="text-xl font-black text-gray-900 tracking-tight">
          {editingTour ? 'Edit Tour Package' : 'Add Tour Package'}
        </h1>
        <button type="button" onClick={onClose} className="text-2xl">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6 flex-1 overflow-y-auto pb-32">

        {/* Tour Title */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tour Title</label>
          <input 
            type="text" 
            placeholder="Enter tour title" 
            value={formData.title} 
            onChange={e => setFormData({...formData, title: e.target.value})} 
            className="w-full p-4 bg-white border border-gray-100 rounded-xl focus:ring-2 focus:ring-emerald-400 outline-none shadow-sm placeholder-gray-300" 
            required 
          />
        </div>

        {/* Location */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Location</label>
          <input 
            type="text" 
            placeholder="Enter tour location" 
            value={formData.location} 
            onChange={e => setFormData({...formData, location: e.target.value})} 
            className="w-full p-4 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300" 
          />
        </div>

        {/* Start & End Date */}
        <div className="flex space-x-4">
          <div className="flex-1 space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Start Date</label>
            <input 
              type="date" 
              value={formData.startDate} 
              onChange={e => setFormData({...formData, startDate: e.target.value})} 
              className="w-full p-4 bg-white border border-gray-100 rounded-xl text-gray-500 shadow-sm" 
            />
          </div>
          <div className="flex-1 space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">End Date</label>
            <input 
              type="date" 
              value={formData.endDate} 
              onChange={e => setFormData({...formData, endDate: e.target.value})} 
              className="w-full p-4 bg-white border border-gray-100 rounded-xl text-gray-500 shadow-sm" 
            />
          </div>
        </div>

        {/* Description */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">What is it about</label>
          <textarea 
            placeholder="Enter description" 
            rows="5" 
            value={formData.description} 
            onChange={e => setFormData({...formData, description: e.target.value})} 
            className="w-full p-4 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300 resize-none" 
          />
        </div>

        {/* Important Notes */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Important Notes:</label>
          <textarea 
            placeholder="Enter Important Notes of the tour" 
            rows="3" 
            value={formData.importantNotes} 
            onChange={e => setFormData({...formData, importantNotes: e.target.value})} 
            className="w-full p-4 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300 resize-none" 
          />
        </div>

        {/* Upload Cover Picture UI (對齊 Figma) */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Upload cover picture</label>
          <div className="border-2 border-dashed border-gray-100 rounded-[30px] p-10 text-center bg-gray-50 hover:bg-gray-100 transition-colors">
             <div className="flex flex-col items-center">
                <div className="bg-white p-3 rounded-full shadow-sm mb-3">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                   </svg>
                </div>
                <p className="font-bold text-gray-700 text-sm">Click to upload</p>
                <p className="text-[10px] text-gray-400 mt-1 uppercase tracking-tighter">SVG, PNG, JPG or GIF (max. 800x400px)</p>
             </div>
          </div>
        </div>

        {/* Capacity */}
        <div className="space-y-2">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Capacity (/day)</label>
          <input 
            type="number" 
            placeholder="Enter the maximum daily capacity" 
            value={formData.capacity} 
            onChange={e => setFormData({...formData, capacity: e.target.value})} 
            className="w-full p-4 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300" 
          />
        </div>

        {/* Price & Discount */}
        <div className="flex space-x-4">
          <div className="flex-1 space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Price (in AUD)</label>
            <div className="relative">
              <span className="absolute left-4 top-4 text-gray-400 font-bold">$</span>
              <input 
                type="number" 
                placeholder="Enter price" 
                value={formData.price} 
                onChange={e => setFormData({...formData, price: e.target.value})} 
                className="w-full p-4 pl-8 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300" 
                required 
              />
            </div>
          </div>
          <div className="flex-1 space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Discount</label>
            <input 
              type="number" 
              placeholder="Enter price" 
              value={formData.discount} 
              onChange={e => setFormData({...formData, discount: e.target.value})} 
              className="w-full p-4 bg-white border border-gray-100 rounded-xl outline-none shadow-sm placeholder-gray-300" 
            />
          </div>
        </div>

        {/* Status */}
        <div className="space-y-2 pb-10">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Status</label>
          <div className="relative">
            <select 
              value={formData.status} 
              onChange={e => setFormData({...formData, status: e.target.value})} 
              className="w-full p-4 bg-white border border-gray-100 rounded-xl appearance-none outline-none shadow-sm text-gray-700"
            >
              <option value="Available">Available</option>
              <option value="Unavailable">Unavailable</option>
            </select>
            <div className="absolute right-4 top-5 pointer-events-none text-emerald-500">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
               </svg>
            </div>
          </div>
        </div>

        {/* Submit Button (對齊 Figma) */}
        <div className="pt-4 pb-20">
          <button 
            type="submit" 
            className="w-full bg-emerald-500 text-white font-black text-lg py-5 rounded-[24px] shadow-xl shadow-emerald-100 hover:bg-emerald-600 active:scale-95 transition-all"
          >
            Submit
          </button>

          {editingTour && (
            <button 
              type="button" 
              onClick={handleDelete} 
              className="w-full text-red-500 font-bold py-4 mt-2 hover:bg-red-50 rounded-xl transition"
            >
              Delete Tour Package
            </button>
          )}
        </div>
      </form>
    </div>
  );
};

export default TourForm;
